const users = $input.all().map(item => item.json);
const weekRange = $('Compute Week Range').first().json;
const userList = [
  { user_id: "00000000-0000-0000-0000-000000000000", is_generic: true },
  ...users.map(u => ({ user_id: u.user_id, is_generic: false }))
];
return userList.map(u => ({ json: { ...u, ...weekRange } }));

const input = $input.first().json;
const loopData = $('Loop Through Users').first().json;
if (loopData.is_generic) {
  return [{ json: {
    user_id: null,
    company_name: null,
    company_domain: null,
    competitor_ids: [],
    competitor_names: [],
    competitor_domains: [],
    user_industry: null,
    is_personalized: false,
    week_start: loopData.week_start,
    week_end: loopData.week_end
  }}];
}
return [{ json: {
  user_id: loopData.user_id,
  company_name: input.company_name || null,
  company_domain: input.company_domain || null,
  competitor_ids: input.competitor_ids || [],
  competitor_names: input.competitor_names || [],
  competitor_domains: input.competitor_domains || [],
  user_industry: input.user_industry || null,
  is_personalized: !!(input.company_name),
  week_start: loopData.week_start,
  week_end: loopData.week_end
}}];

const signals = $input.all().map(item => item.json);
const userContext = $('Format User Context').first().json;
const weekRange = { week_start: userContext.week_start, week_end: userContext.week_end };

const SHIP_CAPS = {
  messaging: 8, narrative: 5, icp: 5, horizon: 3, objection: 5,
  pricing: 4, proof: 3, distribution: 3, hiring: 2, launch_decay: 2, experiment: 5
};
const MAX_TOTAL = 45;
const WEIGHTS = { severity: 8, recency: 30, confidence: 15, source_quality: 15 };

function filterByUserCompetitors(allSignals, ctx) {
  if (!ctx || !ctx.competitor_ids || ctx.competitor_ids.length === 0) {
    return allSignals;
  }
  const competitorIds = new Set(ctx.competitor_ids);
  const competitorDomains = new Set((ctx.competitor_domains || []).map(d => d?.toLowerCase()));
  const competitorNames = new Set((ctx.competitor_names || []).map(n => n?.toLowerCase()));

  return allSignals.filter(signal => {
    if (signal.company_id && competitorIds.has(signal.company_id)) return true;
    const evidenceUrls = signal.evidence_urls || [];
    for (const url of evidenceUrls) {
      const urlLower = (url || '').toLowerCase();
      for (const domain of competitorDomains) {
        if (domain && urlLower.includes(domain)) return true;
      }
    }
    const titleLower = (signal.title || '').toLowerCase();
    const summaryLower = (signal.summary || '').toLowerCase();
    for (const name of competitorNames) {
      if (name && (titleLower.includes(name) || summaryLower.includes(name))) return true;
    }
    return false;
  });
}

const filteredSignals = filterByUserCompetitors(signals, userContext);
let relevantSignals = filteredSignals;

if (relevantSignals.length < 10 && userContext.user_industry) {
  const industrySignals = signals.filter(s => {
    if (relevantSignals.includes(s)) return false;
    const meta = s.meta || {};
    return meta.industry === userContext.user_industry;
  });
  industrySignals.forEach(s => { s._widened = 'industry'; });
  relevantSignals = [...relevantSignals, ...industrySignals];
}

if (relevantSignals.length < 10) {
  const horizonSignals = signals.filter(s =>
    !relevantSignals.includes(s) && s.signal_type === 'horizon'
  );
  horizonSignals.forEach(s => { s._widened = 'horizon'; });
  relevantSignals = [...relevantSignals, ...horizonSignals];
}

if (relevantSignals.length < 5) {
  const highSeverity = signals.filter(s =>
    !relevantSignals.includes(s) && (s.severity || 0) >= 4
  );
  highSeverity.forEach(s => { s._widened = 'market'; });
  relevantSignals = [...relevantSignals, ...highSeverity];
}

function computeScore(signal) {
  const now = new Date();
  const createdAt = new Date(signal.created_at);
  const daysOld = (now - createdAt) / (1000 * 60 * 60 * 24);
  const severityScore = (signal.severity || 3) * WEIGHTS.severity;
  const recencyScore = Math.max(0, WEIGHTS.recency - (daysOld * 4.3));
  const confidenceScore = (parseFloat(signal.confidence) || 0.5) * WEIGHTS.confidence;
  const sourceQuality = signal.source_quality || 'medium';
  const sourceScore = sourceQuality === 'high' ? 15 : sourceQuality === 'medium' ? 10 : 5;
  return Math.round((severityScore + recencyScore + confidenceScore + sourceScore) * 100) / 100;
}

const enrichedSignals = relevantSignals.map(signal => ({
  ...signal,
  score: computeScore(signal),
  summary_short: signal.summary ? signal.summary.substring(0, 100) + (signal.summary.length > 100 ? '...' : '') : ''
}));

const sections = ['messaging', 'narrative', 'icp', 'horizon', 'objection', 'pricing', 'proof', 'distribution', 'hiring', 'launch_decay', 'experiment'];
const selectedBySection = {};
let totalSelected = [];

for (const section of sections) {
  const cap = SHIP_CAPS[section] || 6;
  const sectionSignals = enrichedSignals.filter(s => s.signal_type === section).sort((a, b) => b.score - a.score).slice(0, cap);
  selectedBySection[section] = sectionSignals;
  totalSelected = totalSelected.concat(sectionSignals);
}

if (totalSelected.length > MAX_TOTAL) {
  totalSelected.sort((a, b) => b.score - a.score);
  totalSelected = totalSelected.slice(0, MAX_TOTAL);
}

const signalSummaries = {};
for (const section of sections) {
  signalSummaries[section] = (selectedBySection[section] || []).map(s => ({
    id: s.id, severity: s.severity, title: s.title, summary_short: s.summary_short, score: s.score
  }));
}

const isPersonalized = userContext.is_personalized;
const companyName = userContext.company_name || 'your company';
const competitorsList = userContext.competitor_names?.join(', ') || 'competitors';

const systemPrompt = `You are a GTM intelligence analyst creating weekly packets for ${isPersonalized ? companyName + "'s" : 'a'} PMM team.\n${isPersonalized ? `COMPANY: ${companyName}\nTRACKED COMPETITORS: ${competitorsList}\nFrame insights as "${companyName} vs [Competitor]" where relevant.` : ''}\nFor widened signals, prefix with context: industry=>"In your industry sector", horizon=>"Market-wide trend", market=>"Notable cross-market development"\nOutput STRICT JSON only.\nSchema: { "packet_title": "string", "exec_summary": ["max 7 bullets"], "sections": { "messaging": {"summary":"str","highlights":[],"action_items":[]}, "narrative":{...}, "icp":{...}, "horizon":{...}, "objection":{...} }, "key_questions": ["3-5 items"], "bets": [{"hypothesis":"str","signal_ids":[],"confidence":"low|medium|high"}], "predictions": [{"prediction":"str","timeframe":"str","confidence":0.0-1.0,"signals":[]}], "action_mapping": {"this_week":[{"action":"str","owner":"str","priority":"str"}],"monitor":[{"signal":"str","trigger":"str","action":"str"}]} }`;

const userContent = `Week: ${weekRange.week_start} to ${weekRange.week_end}\n${isPersonalized ? `Company: ${companyName}` : ''}\nTotal signals: ${signals.length}, Filtered: ${filteredSignals.length}, Selected: ${totalSelected.length}\n\nMESSAGING: ${JSON.stringify(signalSummaries.messaging)}\nNARRATIVE: ${JSON.stringify(signalSummaries.narrative)}\nICP: ${JSON.stringify(signalSummaries.icp)}\nHORIZON: ${JSON.stringify(signalSummaries.horizon)}\nOBJECTION: ${JSON.stringify(signalSummaries.objection)}\n\nGenerate weekly GTM intelligence packet.`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 3000,
  temperature: 0.3,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{ json: {
  week_start: weekRange.week_start,
  week_end: weekRange.week_end,
  user_id: userContext.user_id,
  user_company_name: userContext.company_name,
  is_personalized: isPersonalized,
  competitor_names: userContext.competitor_names || [],
  total_signals: signals.length,
  filtered_signals: filteredSignals.length,
  selected_count: totalSelected.length,
  selected_signals: totalSelected,
  signal_summaries: signalSummaries,
  anthropic_body: anthropicBody
}}];

const resp = $input.first().json;
const selectData = $('Score + Select Top Signals').first().json;

let packetData;
try {
  const content = resp.content?.[0]?.text || '{}';
  const cleaned = content.replace(/^```json?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
  packetData = JSON.parse(cleaned);
} catch (e) {
  packetData = {
    packet_title: `Week of ${selectData.week_start}: Intelligence Packet`,
    exec_summary: ['Signal synthesis failed - manual review required'],
    sections: {
      messaging: { summary: 'Parsing error', highlights: [], action_items: [] },
      narrative: { summary: 'Parsing error', highlights: [], action_items: [] },
      icp: { summary: 'Parsing error', highlights: [], action_items: [] },
      horizon: { summary: 'Parsing error', highlights: [], action_items: [] },
      objection: { summary: 'Parsing error', highlights: [], action_items: [] }
    },
    key_questions: ['Review raw signals for this week'],
    bets: [],
    predictions: [],
    action_mapping: { this_week: [], monitor: [] }
  };
}

return [{ json: {
  ...selectData,
  packet: packetData
}}];

const weekRange = $('Format User Context').first().json;
const packetResult = $('Upsert Packet').first().json;
const scoreResult = $('Score + Select Top Signals').first().json;
const userCtx = $('Format User Context').first().json;

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const packetId = packetResult.id;

const signals = scoreResult.selected_signals.filter(s =>
  ['messaging', 'narrative', 'icp'].includes(s.signal_type)
);

const MAX_OBJECTIONS = 12;
const MAX_EVIDENCE_PER_OBJECTION = 2;
const isPersonalized = userCtx.is_personalized;
const companyName = userCtx.company_name || 'your company';

const systemPrompt = `You are a sales enablement expert building an Objection Library from GTM signals${isPersonalized ? ` for ${companyName}'s sales team` : ''}.
CRITICAL: Output STRICT JSON only.
Schema:
{
  "objections": [
    {
      "category": "price_value|timing|complexity|risk|fit|competition|inertia",
      "objection_text": "string",
      "frequency": "high|medium|low",
      "personas": ["string"],
      "segments": ["string"],
      "evidence_urls": ["string (max ${MAX_EVIDENCE_PER_OBJECTION})"],
      "rebuttal": {
        "acknowledge": "string",
        "reframe": "string",
        "proof": "string",
        "talk_track": "string"
      },
      "signal_ids": ["uuid"],
      "is_new_this_week": true|false
    }
  ],
  "summary": {
    "total_objections": number,
    "top_category": "string",
    "new_this_week": number,
    "trending_up": ["string"],
    "trending_down": ["string"]
  }
}
CONSTRAINTS: Max ${MAX_OBJECTIONS} objections. Max ${MAX_EVIDENCE_PER_OBJECTION} evidence URLs per objection. Each objection must have at least one signal_id. Rebuttals must be specific.`;

const userContent = `Week: ${weekStart} to ${weekEnd}\nPacket ID: ${packetId}\n${isPersonalized ? `Company: ${companyName}` : ''}\n\nBuild an Objection Library from these signals:\n\nSIGNALS (${signals.length} total):\n${JSON.stringify(signals.map(s => ({ id: s.id, type: s.signal_type, severity: s.severity, title: s.title, summary: s.summary, evidence_urls: s.evidence_urls || [] })), null, 2)}\n\nExtract objections mentioned or implied in these signals. Group by category, provide evidence-linked rebuttals.`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2500,
  temperature: 0.2,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    builder_type: 'objection_library',
    week_start: weekStart,
    week_end: weekEnd,
    packet_id: packetId,
    user_id: userCtx.user_id || null,
    user_company_name: userCtx.company_name || null,
    is_personalized: isPersonalized || false,
    input_signal_count: signals.length,
    input_signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

const anthropicResponse = $input.first().json;
const builderData = $('Builder: Objection Library').first().json;

const content = anthropicResponse.content[0].text;

let objectionLibrary;
try {
  const cleaned = content.replace(/^```json?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
  objectionLibrary = JSON.parse(cleaned);
} catch (e) {
  objectionLibrary = { objections: [], summary: { total_objections: 0, top_category: 'unknown', new_this_week: 0, trending_up: [], trending_down: [] } };
}

if (!objectionLibrary.objections || !Array.isArray(objectionLibrary.objections)) {
  objectionLibrary.objections = [];
}

if (!objectionLibrary.summary) {
  objectionLibrary.summary = {
    total_objections: objectionLibrary.objections.length,
    top_category: objectionLibrary.objections[0]?.category || 'unknown',
    new_this_week: objectionLibrary.objections.filter(o => o.is_new_this_week).length,
    trending_up: [],
    trending_down: []
  };
}

return [{
  json: {
    week_start: builderData.week_start,
    week_end: builderData.week_end,
    packet_id: builderData.packet_id,
    content_json: objectionLibrary,
    content_md: JSON.stringify(objectionLibrary, null, 2),
    included_signal_ids: builderData.input_signal_ids,
    objection_count: objectionLibrary.objections.length,
    user_id: builderData.user_id,
    user_company_name: builderData.user_company_name,
    is_personalized: builderData.is_personalized
  }
}];

const weekRange = $('Format User Context').first().json;
const packetResult = $('Upsert Packet').first().json;
const scoreResult = $('Score + Select Top Signals').first().json;
const userCtx = $('Format User Context').first().json;

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const packetId = packetResult.id;
const signals = scoreResult.selected_signals;
const isPersonalized = userCtx.is_personalized;
const companyName = userCtx.company_name || 'your company';

const PHRASE_CATEGORIES = ['pain_points', 'desired_outcomes', 'objections', 'trigger_events', 'evaluation_criteria', 'competitive_mentions', 'budget_signals', 'timeline_indicators'];

const systemPrompt = `You are a PMM assistant specialized in creating buyer language swipe files${isPersonalized ? ` for ${companyName}'s team` : ''}. Your task is to extract authentic buyer phrases from market signals and organize them by persona and category. Rules: 1) Extract EXACT phrases when possible, light paraphrasing only when needed for clarity. 2) Tag each phrase with the persona most likely to use it. 3) Maximum 30 phrases total, maximum 5 per persona. 4) Include source attribution for traceability. 5) Focus on language that reveals pain, desired outcomes, objections, and buying triggers. IMPORTANT: If you need to include quotation marks inside a string value, you MUST escape them with a backslash like this: \\"quoted text\\". Never put unescaped double quotes inside JSON string values. Output raw JSON only without markdown code fences. Output valid JSON with structure:\n\n { "swipe_file_version": "1.0", "phrases": [{ "text": "phrase", "category": "category_name", "persona": "persona_tag", "source_signal_id": "uuid", "confidence": 0.9 }], "persona_summary": { "persona_name": { "phrase_count": 5, "top_categories": ["cat1", "cat2"] } } }`;

const signalSummaries = signals.map(s => "Signal ID: " + s.id + " | Type: " + s.signal_type + " | Title: " + s.title + " | Summary: " + s.summary).join(" --- ");

const userContent = "Analyze these " + signals.length + " signals from the week of " + weekStart + " to " + weekEnd + (isPersonalized ? " for " + companyName : "") + " and extract buyer language phrases. Categories to extract: " + PHRASE_CATEGORIES.join(', ') + ". Signals: " + signalSummaries + ". Return a JSON swipe file with extracted phrases tagged by persona and category.";

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    builder_type: 'swipe_file',
    week_start: weekStart,
    week_end: weekEnd,
    packet_id: packetId,
    user_id: userCtx.user_id || null,
    user_company_name: userCtx.company_name || null,
    is_personalized: isPersonalized || false,
    input_signal_count: signals.length,
    input_signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

const anthropicResponse = $input.first().json;
const builderData = $('Builder: Swipe File').first().json;

const content = anthropicResponse.content[0].text;

let swipeFile;
try {
  const jsonMatch = content.match(/```json?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    swipeFile = JSON.parse(jsonMatch[1]);
  } else {
    swipeFile = JSON.parse(content);
  }
} catch (e) {
  swipeFile = { phrases: [], persona_summary: {} };
}

if (!swipeFile.phrases || !Array.isArray(swipeFile.phrases)) {
  swipeFile.phrases = [];
}

return [{
  json: {
    week_start: builderData.week_start,
    week_end: builderData.week_end,
    packet_id: builderData.packet_id,
    content_json: swipeFile,
    content_md: JSON.stringify(swipeFile, null, 2),
    included_signal_ids: builderData.input_signal_ids,
    phrase_count: swipeFile.phrases.length,
    user_id: builderData.user_id,
    user_company_name: builderData.user_company_name,
    is_personalized: builderData.is_personalized
  }
}];

const weekRange = $('Format User Context').first().json;
const packetResult = $('Upsert Packet').first().json;
const scoreResult = $('Score + Select Top Signals').first().json;
const userCtx = $('Format User Context').first().json;

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const packetId = packetResult.id;
const isPersonalized = userCtx.is_personalized;
const companyName = userCtx.company_name || 'your company';
const competitorNames = userCtx.competitor_names || [];

const signals = scoreResult.selected_signals.filter(s =>
  ['messaging', 'icp'].includes(s.signal_type)
);

const MAX_COMPETITORS = isPersonalized ? Math.min(competitorNames.length, 5) : 3;

const systemPrompt = `You are a competitive intelligence expert building Battlecards from GTM signals${isPersonalized ? ` for ${companyName}` : ''}.
Battlecards are delta-focused: they emphasize WHAT CHANGED THIS WEEK and the implications.
${isPersonalized ? `COMPANY: ${companyName}\nTRACKED COMPETITORS: ${competitorNames.join(', ')}\nBuild battlecards ONLY for the tracked competitors listed above.` : ''}
CRITICAL: Output STRICT JSON only. IMPORTANT: If you need to include quotation marks inside a string value, you MUST escape them with a backslash.
Schema:
{
  "battlecards": [
    {
      "competitor_name": "string",
      "what_changed_this_week": [
        {
          "change": "string",
          "implication": "string",
          "counter_move": "string",
          "signal_ids": ["uuid"],
          "evidence_urls": ["string"]
        }
      ],
      "talk_tracks": [
        {
          "scenario": "string",
          "opener": "string",
          "key_points": ["string (3 bullets max)"],
          "proof_point": "string"
        }
      ],
      "landmines": [
        {
          "claim_to_avoid": "string",
          "why": "string",
          "alternative": "string"
        }
      ],
      "win_themes": ["string"],
      "lose_themes": ["string"],
      "ideal_battleground": "string"
    }
  ],
  "summary": {
    "competitors_covered": number,
    "total_changes_this_week": number,
    "highest_priority_competitor": "string",
    "key_market_shifts": ["string"]
  }
}
CONSTRAINTS: Max ${MAX_COMPETITORS} competitors. Focus on CHANGES this week. Talk tracks must be specific. Landmines are critical.`;

const userContent = `Week: ${weekStart} to ${weekEnd}\nPacket ID: ${packetId}\n${isPersonalized ? `Company: ${companyName}\nTracked Competitors: ${competitorNames.join(', ')}` : ''}\n\nBuild Battlecards from these competitive signals:\n\nSIGNALS (${signals.length} total):\n${JSON.stringify(signals.map(s => ({ id: s.id, type: s.signal_type, severity: s.severity, title: s.title, summary: s.summary, evidence_urls: s.evidence_urls || [] })), null, 2)}\n\nInstructions:\n1. Identify up to ${MAX_COMPETITORS} competitors${isPersonalized ? ' from the tracked list' : ''}\n2. Focus on WHAT CHANGED this week\n3. Provide specific talk tracks\n4. Highlight landmines\n5. Include win/lose themes`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 3000,
  temperature: 0.2,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    builder_type: 'battlecards',
    week_start: weekStart,
    week_end: weekEnd,
    packet_id: packetId,
    user_id: userCtx.user_id || null,
    user_company_name: userCtx.company_name || null,
    is_personalized: isPersonalized || false,
    input_signal_count: signals.length,
    input_signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

const anthropicResponse = $input.first().json;
const builderData = $('Builder: Battlecards').first().json;

const rawContent = anthropicResponse.content[0].text;
const cleaned = rawContent.replace(/^```json?\s*\n?/, '').replace(/^```\s*\n?/, '').replace(/\n?```\s*$/, '').trim();

let battlecardsData;
try {
  battlecardsData = JSON.parse(cleaned);
} catch (e) {
  battlecardsData = { battlecards: [], summary: { competitors_covered: 0, total_changes_this_week: 0, highest_priority_competitor: 'unknown', key_market_shifts: [] } };
}

if (!battlecardsData.battlecards || !Array.isArray(battlecardsData.battlecards)) {
  battlecardsData.battlecards = [];
}

const items = battlecardsData.battlecards.map(card => ({
  json: {
    competitor_name: card.competitor_name,
    week_start: builderData.week_start,
    week_end: builderData.week_end,
    content_md: JSON.stringify(card, null, 2),
    included_signal_ids: card.what_changed_this_week?.flatMap(c => c.signal_ids || []) || [],
    what_changed_summary: card.what_changed_this_week?.map(c => c.change).join('; ') || '',
    user_id: builderData.user_id,
    user_company_name: builderData.user_company_name,
    is_personalized: builderData.is_personalized
  }
}));

if (items.length === 0) {
  return [{ json: { _empty: true, user_id: builderData.user_id } }];
}

return items;
